    60→/**
    61→ * Maximo Webhook Event Types
    62→ */
    63→type MaximoWebhookEventType =
    64→  | 'wo_status_changed'
    65→  | 'wo_created'
    66→  | 'wo_updated'
    67→  | 'wo_cancelled';
    68→
    69→/**
    70→ * Maximo Webhook Payload
    71→ *
    72→ * Payload sent by Maximo when a work order status changes.
    73→ */
    74→interface MaximoWebhookPayload {
    75→  /** Event type */
    76→  event: MaximoWebhookEventType;
    77→  /** Work order number (e.g., "WO-2026-ABC123") */
    78→  wonum: string;
    79→  /** New status (e.g., "INPRG", "COMP") */
    80→  status?: MaximoWoStatus;
    81→  /** Timestamp of the change (ISO 8601) */
    82→  changedate: string;
    83→  /** Optional: Site ID */
    84→  siteid?: string;
    85→  /** Optional: Asset number (train number) */
    86→  assetnum?: string;
    87→  /** Optional: Actual start date */
    88→  actstart?: string;
    89→  /** Optional: Actual finish date */
    90→  actfinish?: string;
    91→  /** Optional: Actual labor hours */
    92→  actlabhrs?: number;
    93→  /** Optional: MMS schedule ID backreference */
    94→  mms_schedule_id?: string;
    95→}
    96→
    97→/**
    98→ * Validate Maximo webhook payload
    99→ */
   100→function validateWebhookPayload(
   101→  payload: unknown
   102→): { valid: true; data: MaximoWebhookPayload } | { valid: false; error: string } {
   103→  if (typeof payload !== 'object' || payload === null) {
   104→    return { valid: false, error: 'Payload must be an object' };
   105→  }
   106→
   107→  const p = payload as Record<string, unknown>;
   108→
   109→  // Required: event
   110→  if (!p.event || typeof p.event !== 'string') {
   111→    return { valid: false, error: 'Missing or invalid event field' };
   112→  }
   113→
   114→  const validEvents: MaximoWebhookEventType[] = [
   115→    'wo_status_changed',
   116→    'wo_created',
   117→    'wo_updated',
   118→    'wo_cancelled',
   119→  ];
   120→  if (!validEvents.includes(p.event as MaximoWebhookEventType)) {
   121→    return { valid: false, error: `Invalid event type: ${p.event}` };
   122→  }
   123→
   124→  // Required: wonum
   125→  if (!p.wonum || typeof p.wonum !== 'string') {
   126→    return { valid: false, error: 'Missing or invalid wonum field' };
   127→  }
   128→
   129→  // Required: changedate
   130→  if (!p.changedate || typeof p.changedate !== 'string') {
   131→    return { valid: false, error: 'Missing or invalid changedate field' };
   132→  }
   133→
   134→  // Validate changedate is valid ISO 8601
   135→  const changeDate = new Date(p.changedate);
   136→  if (isNaN(changeDate.getTime())) {
   137→    return { valid: false, error: 'changedate must be valid ISO 8601 format' };
   138→  }
   139→
   140→  // Optional: status (required for wo_status_changed)
   141→  if (p.event === 'wo_status_changed') {
   142→    if (!p.status || typeof p.status !== 'string') {
   143→      return { valid: false, error: 'status is required for wo_status_changed event' };
   144→    }
   145→
   146→    const validStatuses: MaximoWoStatus[] = ['WAPPR', 'APPR', 'INPRG', 'COMP', 'CLOSE', 'CAN'];
   147→    if (!validStatuses.includes(p.status as MaximoWoStatus)) {
   148→      return { valid: false, error: `Invalid status: ${p.status}` };
   149→    }
   150→  }
   151→
   152→  return {
   153→    valid: true,
   154→    data: {
   155→      event: p.event as MaximoWebhookEventType,
   156→      wonum: p.wonum as string,
   157→      status: p.status as MaximoWoStatus | undefined,
   158→      changedate: p.changedate as string,
   159→      siteid: typeof p.siteid === 'string' ? p.siteid : undefined,
   160→      assetnum: typeof p.assetnum === 'string' ? p.assetnum : undefined,
   161→      actstart: typeof p.actstart === 'string' ? p.actstart : undefined,
   162→      actfinish: typeof p.actfinish === 'string' ? p.actfinish : undefined,
   163→      actlabhrs: typeof p.actlabhrs === 'number' ? p.actlabhrs : undefined,
   164→      mms_schedule_id: typeof p.mms_schedule_id === 'string' ? p.mms_schedule_id : undefined,
   165→    },
   166→  };
   167→}
   168→
   169→/**
   170→ * POST /integration/webhooks/maximo
   171→ *
   172→ * Receive CM/WO status updates from Maximo.
   173→ *
   174→ * This endpoint is called by Maximo when:
   175→ * - Work order status changes (WAPPR → APPR → INPRG → COMP → CLOSE)
   176→ * - Work order is cancelled (CAN)
   177→ * - Actual labor hours are recorded
   178→ *
   179→ * The webhook updates the shadow record and locks the PM if necessary.
   180→ *
   181→ * @security This endpoint should be protected by Maximo webhook authentication
   182→ * (e.g., shared secret, IP allowlist, or mutual TLS)
   183→ *
   184→ * @see specs/007-integration.md Section 7.4.7
   185→ */
   186→integrationRoutes.post('/integration/webhooks/maximo', async (c) => {
   187→  const requestId = getRequestId(c);
   188→  const startTime = Date.now();
   189→
   190→  let payload: MaximoWebhookPayload;
   191→
   192→  try {
   193→    const body = await c.req.json();
   194→    const validation = validateWebhookPayload(body);
   195→
   196→    if (!validation.valid) {
   197→      logger.warn({ requestId, error: validation.error }, 'Invalid Maximo webhook payload');
   198→      return c.json(
   199→        error(ErrorCodes.VALIDATION_ERROR, validation.error, requestId),
   200→        400
   201→      );
   202→    }
   203→
   204→    payload = validation.data;
   205→  } catch (err) {
   206→    logger.warn({ requestId, error: err }, 'Failed to parse Maximo webhook payload');
   207→    return c.json(
   208→      error(ErrorCodes.VALIDATION_ERROR, 'Invalid JSON payload', requestId),
   209→      400
   210→    );
   211→  }
   212→
   213→  logger.info(
   214→    { requestId, event: payload.event, wonum: payload.wonum, status: payload.status },
   215→    'Received Maximo webhook'
   216→  );
   217→
   218→  // Using imported db singleton
   219→
   220→  // Find shadow record by Maximo WO number
   221→  const shadowRecord = await db.query.maximoShadowRecords.findFirst({
   222→    where: eq(maximoShadowRecords.maximoWoNum, payload.wonum),
   223→  });
   224→
   225→  if (!shadowRecord) {
   226→    // Check if we have an mms_schedule_id backreference
   227→    if (payload.mms_schedule_id && isValidUuid(payload.mms_schedule_id)) {
   228→      // Try to find shadow record by PM schedule ID
   229→      const shadowByPm = await db.query.maximoShadowRecords.findFirst({
   230→        where: eq(maximoShadowRecords.pmScheduleId, payload.mms_schedule_id),
   231→      });
   232→
   233→      if (shadowByPm) {
   234→        // Update shadow record with WO number
   235→        await db
   236→          .update(maximoShadowRecords)
   237→          .set({
   238→            maximoWoNum: payload.wonum,
   239→            updatedAt: new Date(),
   240→          })
   241→          .where(eq(maximoShadowRecords.id, shadowByPm.id));
   242→
   243→        logger.info(
   244→          { requestId, shadowRecordId: shadowByPm.id, wonum: payload.wonum },
   245→          'Associated Maximo WO number with existing shadow record'
   246→        );
   247→      }
   248→    }
   249→
   250→    // If still no shadow record, log and return success (idempotent)
   251→    if (!shadowRecord) {
   252→      logger.info(
   253→        { requestId, wonum: payload.wonum },
   254→        'No shadow record found for Maximo WO - may be untracked in MMS'
   255→      );
   256→
   257→      return c.json(
   258→        success({
   259→          received: true,
   260→          processed: false,
   261→          reason: 'No matching shadow record found',
   262→          wonum: payload.wonum,
   263→        }),
   264→        200
   265→      );
   266→    }
   267→  }
   268→
   269→  // Process based on event type
   270→  try {
   271→    let action = 'none';
   272→    let mmsStatusUpdated = false;
   273→    let pmLocked = false;
   274→
   275→    if (payload.event === 'wo_status_changed' && payload.status) {
   276→      // Get the current shadow record (refreshed)
   277→      const currentShadow = await db.query.maximoShadowRecords.findFirst({
   278→        where: eq(maximoShadowRecords.maximoWoNum, payload.wonum),
   279→      });
   280→
   281→      if (currentShadow) {
   282→        const previousMaximoData = currentShadow.maximoData as { status?: string } | null;
   283→        const previousStatus = previousMaximoData?.status;
   284→
   285→        // Update shadow record with new Maximo data
   286→        await db
   287→          .update(maximoShadowRecords)
   288→          .set({
   289→            maximoData: {
   290→              status: payload.status,
   291→              actualStart: payload.actstart,
   292→              actualFinish: payload.actfinish,
   293→              actualLabor: payload.actlabhrs,
   294→              changeDate: payload.changedate,
   295→            },
   296→            lastSyncAt: new Date(),
   297→            syncStatus: 'SYNCED',
   298→            updatedAt: new Date(),
   299→          })
   300→          .where(eq(maximoShadowRecords.id, currentShadow.id));
   301→
   302→        // Map Maximo status to MMS status
   303→        const mmsStatus = MAXIMO_TO_MMS_STATUS[payload.status];
   304→
   305→        // Update PM schedule status
   306→        const pmRecord = await db.query.pmSchedule.findFirst({
   307→          where: eq(pmSchedule.id, currentShadow.pmScheduleId),
   308→        });
   309→
   310→        if (pmRecord) {
   311→          const isLocked = LOCKED_MAXIMO_STATUSES.includes(payload.status);
   312→
   313→          // Update PM schedule
   314→          await db
   315→            .update(pmSchedule)
   316→            .set({
   317→              status: mmsStatus,
   318→              isLocked: isLocked,
   319→              actualStartDate: payload.actstart ? payload.actstart.split('T')[0] : pmRecord.actualStartDate,
   320→              actualEndDate: payload.actfinish ? payload.actfinish.split('T')[0] : pmRecord.actualEndDate,
   321→              actualHours: payload.actlabhrs !== undefined
   322→                ? payload.actlabhrs.toString()
   323→                : pmRecord.actualHours,
   324→              updatedAt: new Date(),
   325→            })
   326→            .where(eq(pmSchedule.id, pmRecord.id));
   327→
   328→          mmsStatusUpdated = true;
   329→          pmLocked = isLocked;
   330→
   331→          logger.info(
   332→            {
   333→              requestId,
   334→              pmScheduleId: pmRecord.id,
   335→              previousStatus,
   336→              newStatus: payload.status,
   337→              mmsStatus,
   338→              isLocked,
   339→            },
   340→            'Updated PM schedule from Maximo webhook'
   341→          );
   342→        }
   343→
   344→        action = 'status_updated';
   345→      }
   346→    } else if (payload.event === 'wo_cancelled') {
   347→      // Handle work order cancellation
   348→      const currentShadow = await db.query.maximoShadowRecords.findFirst({
   349→        where: eq(maximoShadowRecords.maximoWoNum, payload.wonum),
   350→      });
   351→
   352→      if (currentShadow) {
   353→        await db
   354→          .update(maximoShadowRecords)
   355→          .set({
   356→            maximoData: {
   357→              status: 'CAN',
   358→              changeDate: payload.changedate,
   359→            },
   360→            syncStatus: 'SYNCED',
   361→            updatedAt: new Date(),
   362→          })
   363→          .where(eq(maximoShadowRecords.id, currentShadow.id));
   364→
   365→        // Update PM schedule to CANCELLED and locked
   366→        await db
   367→          .update(pmSchedule)
   368→          .set({
   369→            status: 'CANCELLED',
   370→            isLocked: true,
   371→            updatedAt: new Date(),
   372→          })
   373→          .where(eq(pmSchedule.id, currentShadow.pmScheduleId));
   374→
   375→        action = 'wo_cancelled';
   376→        mmsStatusUpdated = true;
   377→        pmLocked = true;
   378→
   379→        logger.info(
   380→          { requestId, pmScheduleId: currentShadow.pmScheduleId, wonum: payload.wonum },
   381→          'PM cancelled from Maximo webhook'
   382→        );
   383→      }
   384→    }
   385→
   386→    const durationMs = Date.now() - startTime;
   387→
   388→    return c.json(
   389→      success({
   390→        received: true,
   391→        processed: true,
   392→        action,
   393→        wonum: payload.wonum,
   394→        event: payload.event,
   395→        mmsStatusUpdated,
   396→        pmLocked,
   397→        durationMs,
   398→      }),
   399→      200
   400→    );
   401→  } catch (err) {
   402→    logger.error({ requestId, error: err, wonum: payload.wonum }, 'Failed to process Maximo webhook');
   403→    return c.json(
   404→      error(
   405→        ErrorCodes.INTERNAL_ERROR,
   406→        'Failed to process webhook',
   407→        requestId,
   408→        { wonum: payload.wonum }
   409→      ),
   410→      500
   411→    );
   412→  }
   413→});
