   635→    );
   636→
   637→    // Transform to API response format
   638→    const conflicts = result.data.map((item) => ({
   639→      id: item.shadowRecord.id,
   640→      pmScheduleId: item.shadowRecord.pmScheduleId,
   641→      maximoWoNum: item.shadowRecord.maximoWoNum,
   642→      syncStatus: item.shadowRecord.syncStatus,
   643→      lastSyncAt: item.shadowRecord.lastSyncAt?.toISOString() ?? null,
   644→      lastSyncError: item.shadowRecord.lastSyncError,
   645→      mmsData: item.shadowRecord.mmsDataSnapshot,
   646→      maximoData: item.shadowRecord.maximoData,
   647→      pmSchedule: {
   648→        id: item.pmSchedule.id,
   649→        trainId: item.pmSchedule.trainId,
   650→        trainNumber: item.pmSchedule.train?.trainNumber,
   651→        pmTypeCode: item.pmSchedule.pmType?.pmCode,
   652→        pmTypeName: item.pmSchedule.pmType?.pmName,
   653→        targetDate: item.pmSchedule.targetDate,
   654→        status: item.pmSchedule.status,
