   657→      createdAt: item.shadowRecord.createdAt?.toISOString() ?? new Date().toISOString(),
   658→      updatedAt: item.shadowRecord.updatedAt?.toISOString() ?? new Date().toISOString(),
   659→    }));
   660→
   661→    return c.json(
   662→      paginatedSuccess(conflicts, {
   663→        page: result.page,
   664→        pageSize: result.pageSize,
   665→        totalItems: result.total,
   666→      }, { durationMs: getRequestDuration(c) })
   667→    );
   668→  } catch (err) {
   669→    logger.error({ requestId, error: err }, 'Failed to list conflicts');
   670→    return c.json(
