   773→          trainId: shadowRecord.pmScheduleEntry.trainId,
   774→          trainNumber: shadowRecord.pmScheduleEntry.train?.trainNumber,
   775→          pmTypeCode: shadowRecord.pmScheduleEntry.pmType?.pmCode,
   776→          pmTypeName: shadowRecord.pmScheduleEntry.pmType?.pmName,
   777→          targetDate: shadowRecord.pmScheduleEntry.targetDate,
   778→          currentStatus: shadowRecord.pmScheduleEntry.status,
   779→          depotCode: shadowRecord.pmScheduleEntry.assignedDepot?.code,
   780→        },
   781→        resolutionOptions: [
   782→          {
   783→            strategy: 'USE_MMS',
   784→            description: 'Overwrite Maximo with MMS data (force push)',
   785→          },
   786→          {
   787→            strategy: 'USE_MAXIMO',
   788→            description: 'Apply Maximo data to MMS (accept Maximo changes)',
