   811→
   812→/**
   813→ * POST /integration/conflicts/:id/resolve
   814→ *
   815→ * Resolve a sync conflict.
   816→ *
   817→ * @param id - PM schedule ID (not shadow record ID)
   818→ * @body resolution - Strategy: "USE_MMS" or "USE_MAXIMO"
   819→ *
   820→ * - USE_MMS: Force push MMS data to Maximo (overwrite)
   821→ * - USE_MAXIMO: Apply Maximo data to MMS (accept Maximo's truth)
   822→ */
   823→integrationRoutes.post('/integration/conflicts/:id/resolve', async (c) => {
   824→  const requestId = getRequestId(c);
   825→  const id = c.req.param('id');
   826→  const service = getService();
   827→
   828→  if (!isValidUuid(id)) {
   829→    return c.json(
   830→      error(ErrorCodes.VALIDATION_ERROR, 'Invalid conflict ID format', requestId),
   831→      400
   832→    );
   833→  }
   834→
   835→  let body: ResolveConflictRequest;
   836→
   837→  try {
   838→    body = await c.req.json();
   839→  } catch {
   840→    return c.json(
   841→      error(ErrorCodes.VALIDATION_ERROR, 'Invalid JSON body', requestId),
   842→      400
   843→    );
   844→  }
   845→
   846→  // Validate resolution
   847→  if (!body.resolution || !['USE_MMS', 'USE_MAXIMO'].includes(body.resolution)) {
   848→    return c.json(
   849→      error(
   850→        ErrorCodes.VALIDATION_ERROR,
   851→        'resolution must be "USE_MMS" or "USE_MAXIMO"',
   852→        requestId
   853→      ),
   854→      400
   855→    );
   856→  }
   857→
   858→  // First, check if this is a shadow record ID or PM schedule ID
   859→  // Using imported db singleton
   860→  let pmScheduleId = id;
   861→
   862→  // Try to find shadow record by ID first
   863→  const shadowById = await db.query.maximoShadowRecords.findFirst({
   864→    where: eq(maximoShadowRecords.id, id),
   865→  });
   866→
   867→  if (shadowById) {
   868→    pmScheduleId = shadowById.pmScheduleId;
   869→  }
   870→
   871→  try {
   872→    // Get user ID from context if available (for audit)
   873→    const user = c.get('user');
   874→    const userId = user?.id;
   875→
   876→    await service.resolveConflict(pmScheduleId, body.resolution, userId);
   877→
   878→    logger.info(
   879→      { requestId, pmScheduleId, resolution: body.resolution, userId },
   880→      'Conflict resolved'
   881→    );
   882→
   883→    return c.json(
   884→      success({
   885→        resolved: true,
   886→        pmScheduleId,
   887→        resolution: body.resolution,
   888→        message:
   889→          body.resolution === 'USE_MMS'
   890→            ? 'MMS data pushed to Maximo'
   891→            : 'Maximo data applied to MMS',
   892→      }, { timing: { durationMs: getRequestDuration(c) } })
   893→    );
   894→  } catch (err) {
   895→    if (err instanceof NotFoundError) {
   896→      return c.json(
   897→        error(ErrorCodes.NOT_FOUND, err.message, requestId),
   898→        404
   899→      );
   900→    }
   901→
   902→    if (err instanceof ValidationError) {
   903→      return c.json(
   904→        error(ErrorCodes.VALIDATION_ERROR, err.message, requestId),
   905→        400
   906→      );
   907→    }
   908→
   909→    logger.error({ requestId, pmScheduleId, error: err }, 'Failed to resolve conflict');
   910→    return c.json(
   911→      error(ErrorCodes.INTERNAL_ERROR, 'Failed to resolve conflict', requestId),
   912→      500
   913→    );
   914→  }
   915→});
