  1202→            }
  1203→          ),
  1204→          423
  1205→        );
  1206→      }
  1207→
  1208→      // Return 409 Conflict for sync conflict
  1209→      if (validation.reason === 'SYNC_CONFLICT') {
  1210→        return c.json(
