  1213→            validation.message ?? 'Unresolved sync conflict',
  1214→            requestId,
  1215→            {
  1216→              reason: validation.reason,
  1217→              suggestion: validation.suggestion,
  1218→            }
  1219→          ),
  1220→          409
  1221→        );
  1222→      }
  1223→
  1224→      // Return 423 for baseline lock
