/**
 * GET /integration/sync/stats
 *
 * Get Maximo sync statistics.
 *
 * Returns counts of shadow records by status, last sync timestamps,
 * and circuit breaker state.
 */
integrationRoutes.get('/integration/sync/stats', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  try {
    const stats = await service.getSyncStats();

    return c.json(
      success({
        pendingRecords: stats.pendingRecords,
        syncedRecords: stats.syncedRecords,
        conflictRecords: stats.conflictRecords,
        errorRecords: stats.errorRecords,
        totalRecords:
          stats.pendingRecords + stats.syncedRecords + stats.conflictRecords + stats.errorRecords,
        lastSyncAt: stats.lastSyncAt?.toISOString() ?? null,
        lastPullAt: stats.lastPullAt?.toISOString() ?? null,
        circuitBreakerState: stats.circuitBreakerState,
        isHealthy: stats.circuitBreakerState === 'CLOSED',
      }, { timing: { durationMs: getRequestDuration(c) } })
    );
  } catch (err) {
    logger.error({ requestId, error: err }, 'Failed to get sync stats');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Failed to get sync statistics', requestId),
      500
    );
  }
});

/**
 * POST /integration/sync/push
 *
 * Trigger push sync (MMS → Maximo).
 *
 * Pushes all pending shadow records to Maximo, creating or updating
 * work orders as needed.
 *
 * @returns Summary of push results
 */
integrationRoutes.post('/integration/sync/push', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  try {
    logger.info({ requestId }, 'Starting push sync to Maximo');

    const result = await service.pushAllPending();

    logger.info(
      { requestId, pushed: result.pushed, errors: result.errors },
      'Push sync completed'
    );

    return c.json(
      success({
        operation: 'push',
        pushed: result.pushed,
        errors: result.errors,
        success: result.errors === 0,
      }, { timing: { durationMs: getRequestDuration(c) } })
    );
  } catch (err) {
    logger.error({ requestId, error: err }, 'Push sync failed');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Push sync failed', requestId),
      500
    );
  }
});

/**
 * POST /integration/sync/pull
 *
 * Trigger pull sync (Maximo → MMS).
 *
 * Queries Maximo for work order status changes and updates MMS
 * PM schedules accordingly.
 *
 * @returns Summary of pull results
 */
integrationRoutes.post('/integration/sync/pull', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  try {
    logger.info({ requestId }, 'Starting pull sync from Maximo');

    const result = await service.pullFromMaximo();

    logger.info(
      {
        requestId,
        processed: result.processed,
        updated: result.updated,
        conflicts: result.conflicts,
        errors: result.errors,
      },
      'Pull sync completed'
    );

    return c.json(
      success({
        operation: 'pull',
        processed: result.processed,
        updated: result.updated,
        conflicts: result.conflicts,
        errors: result.errors,
        success: result.errors === 0,
        details: result.details,
      }, { timing: { durationMs: getRequestDuration(c) } })
    );
  } catch (err) {
    logger.error({ requestId, error: err }, 'Pull sync failed');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Pull sync failed', requestId),
      500
    );
  }
});

/**
 * POST /integration/sync/full
 *
 * Trigger full bidirectional sync.
 *
 * Performs both push (MMS → Maximo) and pull (Maximo → MMS) operations.
 *
 * @returns Combined sync results
 */
integrationRoutes.post('/integration/sync/full', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  try {
    logger.info({ requestId }, 'Starting full bidirectional sync');

    // Push first, then pull
    const pushResult = await service.pushAllPending();
    const pullResult = await service.pullFromMaximo();

    logger.info(
      {
        requestId,
        push: { pushed: pushResult.pushed, errors: pushResult.errors },
        pull: {
          processed: pullResult.processed,
          updated: pullResult.updated,
          conflicts: pullResult.conflicts,
          errors: pullResult.errors,
        },
      },
      'Full sync completed'
    );

    return c.json(
      success({
        operation: 'full',
        push: {
          pushed: pushResult.pushed,
          errors: pushResult.errors,
        },
        pull: {
          processed: pullResult.processed,
          updated: pullResult.updated,
          conflicts: pullResult.conflicts,
          errors: pullResult.errors,
        },
        success: pushResult.errors === 0 && pullResult.errors === 0,
      }, { timing: { durationMs: getRequestDuration(c) } })
    );
  } catch (err) {
    logger.error({ requestId, error: err }, 'Full sync failed');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Full sync failed', requestId),
      500
    );
  }
});

