/**
 * GET /integration/conflicts
 *
 * List all shadow records with sync conflicts.
 *
 * Query Parameters:
 * - page: Page number (default: 1)
 * - pageSize: Items per page (default: 50, max: 200)
 *
 * @returns Paginated list of conflicts with PM details
 */
integrationRoutes.get('/integration/conflicts', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  const pagination = parsePaginationQuery({
    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
  });

  try {
    const result = await service.listShadowRecords(
      { syncStatus: 'CONFLICT' },
      { page: pagination.page, pageSize: pagination.pageSize }
    );

    // Transform to API response format
    const conflicts = result.data.map((item) => ({
      id: item.shadowRecord.id,
      pmScheduleId: item.shadowRecord.pmScheduleId,
      maximoWoNum: item.shadowRecord.maximoWoNum,
      syncStatus: item.shadowRecord.syncStatus,
      lastSyncAt: item.shadowRecord.lastSyncAt?.toISOString() ?? null,
      lastSyncError: item.shadowRecord.lastSyncError,
      mmsData: item.shadowRecord.mmsDataSnapshot,
      maximoData: item.shadowRecord.maximoData,
      pmSchedule: {
        id: item.pmSchedule.id,
        trainId: item.pmSchedule.trainId,
        trainNumber: item.pmSchedule.train?.trainNumber,
        pmTypeCode: item.pmSchedule.pmType?.pmCode,
        pmTypeName: item.pmSchedule.pmType?.pmName,
        targetDate: item.pmSchedule.targetDate,
        status: item.pmSchedule.status,
        depotCode: item.pmSchedule.depot?.code,
      },
      createdAt: item.shadowRecord.createdAt?.toISOString() ?? new Date().toISOString(),
      updatedAt: item.shadowRecord.updatedAt?.toISOString() ?? new Date().toISOString(),
    }));

    return c.json(
      paginatedSuccess(conflicts, {
        page: result.page,
        pageSize: result.pageSize,
        totalItems: result.total,
      }, { durationMs: getRequestDuration(c) })
    );
  } catch (err) {
    logger.error({ requestId, error: err }, 'Failed to list conflicts');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Failed to list conflicts', requestId),
      500
    );
  }
});

/**
 * GET /integration/conflicts/:id
 *
 * Get details of a specific conflict.
 *
 * @param id - Shadow record ID
 * @returns Conflict details with MMS and Maximo data comparison
 */
integrationRoutes.get('/integration/conflicts/:id', async (c) => {
  const requestId = getRequestId(c);
  const id = c.req.param('id');

  if (!isValidUuid(id)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid conflict ID format', requestId),
      400
    );
  }

  // Using imported db singleton

  try {
    const shadowRecord = await db.query.maximoShadowRecords.findFirst({
      where: eq(maximoShadowRecords.id, id),
      with: {
        pmScheduleEntry: {
          with: {
            train: true,
            pmType: true,
            assignedDepot: true,
          },
        },
      },
    });

    if (!shadowRecord) {
      return c.json(
        error(ErrorCodes.NOT_FOUND, 'Conflict not found', requestId),
        404
      );
    }

    if (shadowRecord.syncStatus !== 'CONFLICT') {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Record is not in conflict state', requestId, {
          currentStatus: shadowRecord.syncStatus,
        }),
        400
      );
    }

    const mmsData = shadowRecord.mmsDataSnapshot as {
      trainId: string;
      pmTypeCode: string;
      targetDate: string;
      status: string;
      assignedDepotId?: string;
      assignedHours?: string;
    } | null;

    const maximoData = shadowRecord.maximoData as {
      status?: string;
      schedStart?: string;
      schedFinish?: string;
      actualStart?: string;
      actualFinish?: string;
      actualLabor?: number;
      changeDate?: string;
    } | null;

    return c.json(
      success({
        id: shadowRecord.id,
        pmScheduleId: shadowRecord.pmScheduleId,
        maximoWoNum: shadowRecord.maximoWoNum,
        syncStatus: shadowRecord.syncStatus,
        lastSyncAt: shadowRecord.lastSyncAt?.toISOString() ?? null,
        mmsData: mmsData ? {
          targetDate: mmsData.targetDate,
          status: mmsData.status,
          assignedHours: mmsData.assignedHours,
        } : null,
        maximoData: maximoData ? {
          status: maximoData.status,
          statusLabel: maximoData.status
            ? MAXIMO_STATUS_LABELS[maximoData.status as MaximoWoStatus]
            : null,
          schedStart: maximoData.schedStart,
          schedFinish: maximoData.schedFinish,
          actualStart: maximoData.actualStart,
          actualFinish: maximoData.actualFinish,
          actualLabor: maximoData.actualLabor,
          changeDate: maximoData.changeDate,
        } : null,
        pmSchedule: {
          id: shadowRecord.pmScheduleEntry.id,
          trainId: shadowRecord.pmScheduleEntry.trainId,
          trainNumber: shadowRecord.pmScheduleEntry.train?.trainNumber,
          pmTypeCode: shadowRecord.pmScheduleEntry.pmType?.pmCode,
          pmTypeName: shadowRecord.pmScheduleEntry.pmType?.pmName,
          targetDate: shadowRecord.pmScheduleEntry.targetDate,
          currentStatus: shadowRecord.pmScheduleEntry.status,
          depotCode: shadowRecord.pmScheduleEntry.assignedDepot?.code,
        },
        resolutionOptions: [
          {
            strategy: 'USE_MMS',
            description: 'Overwrite Maximo with MMS data (force push)',
          },
          {
            strategy: 'USE_MAXIMO',
            description: 'Apply Maximo data to MMS (accept Maximo changes)',
          },
        ],
        createdAt: shadowRecord.createdAt?.toISOString() ?? new Date().toISOString(),
        updatedAt: shadowRecord.updatedAt?.toISOString() ?? new Date().toISOString(),
      }, { timing: { durationMs: getRequestDuration(c) } })
    );
  } catch (err) {
    logger.error({ requestId, error: err }, 'Failed to get conflict details');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Failed to get conflict details', requestId),
      500
    );
  }
});

/**
 * Conflict resolution request body
 */
interface ResolveConflictRequest {
  /** Resolution strategy: USE_MMS or USE_MAXIMO */
  resolution: ConflictResolution;
}

/**
 * POST /integration/conflicts/:id/resolve
 *
 * Resolve a sync conflict.
 *
 * @param id - PM schedule ID (not shadow record ID)
 * @body resolution - Strategy: "USE_MMS" or "USE_MAXIMO"
 *
 * - USE_MMS: Force push MMS data to Maximo (overwrite)
 * - USE_MAXIMO: Apply Maximo data to MMS (accept Maximo's truth)
 */
integrationRoutes.post('/integration/conflicts/:id/resolve', async (c) => {
  const requestId = getRequestId(c);
  const id = c.req.param('id');
  const service = getService();

  if (!isValidUuid(id)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid conflict ID format', requestId),
      400
    );
  }

  let body: ResolveConflictRequest;

  try {
    body = await c.req.json();
  } catch {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid JSON body', requestId),
      400
    );
  }

  // Validate resolution
  if (!body.resolution || !['USE_MMS', 'USE_MAXIMO'].includes(body.resolution)) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        'resolution must be "USE_MMS" or "USE_MAXIMO"',
        requestId
      ),
      400
    );
  }

  // First, check if this is a shadow record ID or PM schedule ID
  // Using imported db singleton
  let pmScheduleId = id;

  // Try to find shadow record by ID first
  const shadowById = await db.query.maximoShadowRecords.findFirst({
    where: eq(maximoShadowRecords.id, id),
  });

  if (shadowById) {
    pmScheduleId = shadowById.pmScheduleId;
  }

  try {
    // Get user ID from context if available (for audit)
    const user = c.get('user');
    const userId = user?.id;

    await service.resolveConflict(pmScheduleId, body.resolution, userId);

    logger.info(
      { requestId, pmScheduleId, resolution: body.resolution, userId },
      'Conflict resolved'
    );

    return c.json(
      success({
        resolved: true,
        pmScheduleId,
        resolution: body.resolution,
        message:
          body.resolution === 'USE_MMS'
            ? 'MMS data pushed to Maximo'
            : 'Maximo data applied to MMS',
      }, { timing: { durationMs: getRequestDuration(c) } })
    );
  } catch (err) {
    if (err instanceof NotFoundError) {
      return c.json(
        error(ErrorCodes.NOT_FOUND, err.message, requestId),
        404
      );
    }

    if (err instanceof ValidationError) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, err.message, requestId),
        400
      );
    }

    logger.error({ requestId, pmScheduleId, error: err }, 'Failed to resolve conflict');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Failed to resolve conflict', requestId),
      500
    );
  }
});

// =============================================================================
// Shadow Records (Advanced)
// =============================================================================

/**
 * GET /integration/shadow-records
 *
 * List shadow records with filtering.
 *
 * Query Parameters:
 * - syncStatus: Filter by status (PENDING, SYNCED, CONFLICT, ERROR)
 * - pmScheduleId: Filter by PM schedule ID
 * - maximoWoNum: Filter by Maximo WO number
 * - needsSync: Only show records needing sync (boolean)
 * - page: Page number (default: 1)
 * - pageSize: Items per page (default: 50, max: 200)
 *
 * @returns Paginated list of shadow records
 */
integrationRoutes.get('/integration/shadow-records', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  // Parse query parameters
  const syncStatus = c.req.query('syncStatus');
  const pmScheduleId = c.req.query('pmScheduleId');
  const maximoWoNum = c.req.query('maximoWoNum');
  const needsSyncParam = c.req.query('needsSync');

  // Validate pmScheduleId if provided
  if (pmScheduleId && !isValidUuid(pmScheduleId)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid pmScheduleId format', requestId),
      400
    );
  }

  // Validate syncStatus if provided
  const validStatuses = ['PENDING', 'SYNCED', 'CONFLICT', 'ERROR'];
  if (syncStatus && !validStatuses.includes(syncStatus)) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        `Invalid syncStatus. Must be one of: ${validStatuses.join(', ')}`,
        requestId
      ),
      400
    );
  }

  const pagination = parsePaginationQuery({
    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
  });

  try {
    const result = await service.listShadowRecords(
      {
        syncStatus: syncStatus as 'PENDING' | 'SYNCED' | 'CONFLICT' | 'ERROR' | undefined,
        pmScheduleId: pmScheduleId || undefined,
        maximoWoNum: maximoWoNum || undefined,
        needsSync: needsSyncParam === 'true',
      },
      { page: pagination.page, pageSize: pagination.pageSize }
    );

    // Transform to API response format
    const records = result.data.map((item) => ({
      id: item.shadowRecord.id,
      pmScheduleId: item.shadowRecord.pmScheduleId,
      maximoWoNum: item.shadowRecord.maximoWoNum,
      maximoWoId: item.shadowRecord.maximoWoId,
      syncStatus: item.shadowRecord.syncStatus,
      syncAttempts: item.shadowRecord.syncAttempts,
      lastSyncAt: item.shadowRecord.lastSyncAt?.toISOString() ?? null,
      lastSyncError: item.shadowRecord.lastSyncError,
      nextSyncAt: item.shadowRecord.nextSyncAt?.toISOString() ?? null,
      pmSchedule: {
        id: item.pmSchedule.id,
        trainNumber: item.pmSchedule.train?.trainNumber,
        pmTypeCode: item.pmSchedule.pmType?.pmCode,
        targetDate: item.pmSchedule.targetDate,
        status: item.pmSchedule.status,
        depotCode: item.pmSchedule.depot?.code,
      },
      createdAt: item.shadowRecord.createdAt?.toISOString() ?? new Date().toISOString(),
      updatedAt: item.shadowRecord.updatedAt?.toISOString() ?? new Date().toISOString(),
    }));

    return c.json(
      paginatedSuccess(records, {
        page: result.page,
        pageSize: result.pageSize,
        totalItems: result.total,
      }, { durationMs: getRequestDuration(c) })
    );
  } catch (err) {
    logger.error({ requestId, error: err }, 'Failed to list shadow records');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Failed to list shadow records', requestId),
      500
    );
  }
});

/**
 * POST /integration/shadow-records
 *
 * Create a shadow record for a PM schedule.
 *
 * This initiates Maximo sync tracking for a PM. Called automatically
 * when a PM is scheduled, but can be manually triggered for existing PMs.
 *
 * @body pmScheduleId - PM schedule ID to create shadow record for
 */
integrationRoutes.post('/integration/shadow-records', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  let body: { pmScheduleId: string };

  try {
    body = await c.req.json();
  } catch {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid JSON body', requestId),
      400
    );
  }

  if (!body.pmScheduleId || !isValidUuid(body.pmScheduleId)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid or missing pmScheduleId', requestId),
      400
    );
  }

  try {
    const shadowRecord = await service.createShadowRecord(body.pmScheduleId);

    logger.info(
      { requestId, pmScheduleId: body.pmScheduleId, shadowRecordId: shadowRecord.id },
      'Shadow record created'
    );

    return c.json(
      success({
        id: shadowRecord.id,
        pmScheduleId: shadowRecord.pmScheduleId,
        syncStatus: shadowRecord.syncStatus,
        createdAt: shadowRecord.createdAt?.toISOString() ?? new Date().toISOString(),
      }, { timing: { durationMs: getRequestDuration(c) } }),
      201
    );
  } catch (err) {
    if (err instanceof NotFoundError) {
      return c.json(
        error(ErrorCodes.NOT_FOUND, err.message, requestId),
        404
      );
    }

    logger.error({ requestId, error: err }, 'Failed to create shadow record');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Failed to create shadow record', requestId),
      500
    );
  }
});

/**
 * POST /integration/shadow-records/:id/push
 *
 * Manually trigger push sync for a specific shadow record.
 *
 * @param id - Shadow record ID
 */
integrationRoutes.post('/integration/shadow-records/:id/push', async (c) => {
  const requestId = getRequestId(c);
  const id = c.req.param('id');
  const service = getService();

  if (!isValidUuid(id)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid shadow record ID format', requestId),
      400
    );
  }

  // Using imported db singleton

  // Get PM schedule ID from shadow record
  const shadowRecord = await db.query.maximoShadowRecords.findFirst({
    where: eq(maximoShadowRecords.id, id),
  });

  if (!shadowRecord) {
    return c.json(
      error(ErrorCodes.NOT_FOUND, 'Shadow record not found', requestId),
      404
    );
  }

  try {
    const result = await service.pushToMaximo(shadowRecord.pmScheduleId);

    logger.info(
      { requestId, shadowRecordId: id, pmScheduleId: shadowRecord.pmScheduleId, result },
      'Manual push sync completed'
    );

    return c.json(
      success({
        shadowRecordId: id,
        pmScheduleId: shadowRecord.pmScheduleId,
        action: result.action,
        woNum: result.woNum,
        reason: result.reason,
        error: result.error,
      }, { timing: { durationMs: getRequestDuration(c) } })
    );
  } catch (err) {
    logger.error({ requestId, shadowRecordId: id, error: err }, 'Manual push sync failed');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Push sync failed', requestId),
      500
    );
  }
});

// =============================================================================
// Edit Validation
// =============================================================================

/**
 * POST /integration/validate-edit
 *
 * Validate if a PM can be edited (not locked by Maximo).
 *
 * This should be called before any PM modification operation to check:
 * 1. Maximo status lock (INPRG, COMP, CLOSE, CAN → read-only)
 * 2. Sync conflict (unresolved conflict → must resolve first)
 * 3. Baseline lock (locked in published baseline → needs scenario)
 *
 * @body pmScheduleId - PM schedule ID to validate
 * @returns Validation result with reason if invalid
 */
integrationRoutes.post('/integration/validate-edit', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  let body: { pmScheduleId: string };

  try {
    body = await c.req.json();
  } catch {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid JSON body', requestId),
      400
    );
  }

  if (!body.pmScheduleId || !isValidUuid(body.pmScheduleId)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid or missing pmScheduleId', requestId),
      400
    );
  }

  try {
    const validation = await service.validateEdit(body.pmScheduleId);

    if (!validation.valid) {
      // Return 423 Locked for Maximo status lock
      if (validation.reason === 'MAXIMO_STATUS_LOCK') {
        return c.json(
          error(
            ErrorCodes.MAXIMO_LOCK,
            validation.message ?? 'PM is locked by Maximo',
            requestId,
            {
              reason: validation.reason,
              maximoStatus: validation.maximoStatus,
              maximoWoNum: validation.maximoWoNum,
              suggestion: validation.suggestion,
            }
          ),
          423
        );
      }

      // Return 409 Conflict for sync conflict
      if (validation.reason === 'SYNC_CONFLICT') {
        return c.json(
          error(
            ErrorCodes.CONFLICT,
            validation.message ?? 'Unresolved sync conflict',
            requestId,
            {
              reason: validation.reason,
              suggestion: validation.suggestion,
            }
          ),
          409
        );
      }

      // Return 423 for baseline lock
      if (validation.reason === 'BASELINE_LOCK') {
        return c.json(
          error(
            ErrorCodes.BASELINE_LOCK,
            validation.message ?? 'PM is locked in published baseline',
            requestId,
            {
              reason: validation.reason,
              suggestion: validation.suggestion,
            }
          ),
          423
        );
      }

      // Return 404 for not found
      return c.json(
        error(ErrorCodes.NOT_FOUND, validation.message ?? 'PM not found', requestId),
        404
      );
    }

    return c.json(
      success({
        valid: true,
        pmScheduleId: body.pmScheduleId,
        message: 'PM can be edited',
      }, { timing: { durationMs: getRequestDuration(c) } })
    );
  } catch (err) {
    logger.error({ requestId, error: err }, 'Failed to validate edit');
    return c.json(
      error(ErrorCodes.INTERNAL_ERROR, 'Failed to validate edit', requestId),
      500
    );
  }
});

