</head>
<body>
  <h1>Baseline Drift Alert</h1>

  <div class="alert-box">
    <p><strong>{{trainCount}} trains</strong> have exceeded the drift threshold and may require replanning.</p>
  </div>

  <h2>Summary</h2>
  <table>
    <tr>
      <td>Baseline:</td>
      <td>{{baselineName}} ({{baselineVersion}})</td>
    </tr>
    <tr>
      <td>Analysis Date:</td>
      <td>{{analysisDate}}</td>
    </tr>
    <tr>
      <td>Fleet Avg Drift:</td>
      <td class="metric">{{avgDriftPct}}%</td>
    </tr>
  </table>

  <h2>Trains Requiring Attention</h2>
  <div class="train-list">
    {{#each trains}}
    <div class="train-item">
      <strong>Train {{trainNumber}}</strong> - {{driftPct}}% drift
      <br/>
      <small>Recommendation: {{recommendation}}</small>
    </div>
    {{/each}}
  </div>

  <p>
    <a href="{{dashboardUrl}}">View in Dashboard</a>
  </p>
</body>
</html>
